-- Roegusta Tour live starter seed data.
-- Manually run this file in the Supabase SQL Editor after applying supabase/migrations/0002_tour_results_handbook.sql.
-- This script uses deterministic UUIDs so it can be re-run safely against the seeded rows.
-- It is starter/live seed data only; it intentionally does not wipe unknown future production data.
-- If any cleanup is ever needed, delete only the known deterministic seed IDs in dependency-safe order.
-- Historic match-level rows come from the embedded Matches spreadsheet extract; the Records tab is validation-only and is not inserted to avoid double-counting stats.
-- The 2025 PDF is used only as a structural template for editable 2026 handbook sections; 2025 hotel, flight, restaurant and tee-time details are not seeded into 2026.

begin;

on conflict (id) do update set
  display_name = excluded.display_name,
  initials = excluded.initials,
  active = excluded.active,
  updated_at = excluded.updated_at;

on conflict (id) do update set
  name = excluded.name,
  location = excluded.location,
  start_date = excluded.start_date,
  end_date = excluded.end_date,
  status = excluded.status,
  description = excluded.description,
  updated_at = excluded.updated_at;

on conflict (id) do update set
  attending = excluded.attending,
  tour_handicap = excluded.tour_handicap,
  notes = excluded.notes;

on conflict (id) do update set
  name = excluded.name,
  colour = excluded.colour,
  captain_player_id = excluded.captain_player_id,
  sort_order = excluded.sort_order;

on conflict (id) do nothing;

on conflict (id) do update set
  final_points = excluded.final_points,
  position = excluded.position,
  result_status = excluded.result_status,
  notes = excluded.notes,
  updated_at = excluded.updated_at;

on conflict (id) do update set
  name = excluded.name,
  round_date = excluded.round_date,
  course_name = excluded.course_name,
  tee_time = excluded.tee_time,
  format_label = excluded.format_label,
  notes = excluded.notes,
  status = excluded.status,
  updated_at = excluded.updated_at;

on conflict (id) do update set
  format = excluded.format,
  status = excluded.status,
  side_a_team_id = excluded.side_a_team_id,
  side_b_team_id = excluded.side_b_team_id,
  side_a_label = excluded.side_a_label,
  side_b_label = excluded.side_b_label,
  points_available = excluded.points_available,
  points_side_a = excluded.points_side_a,
  points_side_b = excluded.points_side_b,
  winning_side = excluded.winning_side,
  result_text = excluded.result_text,
  tee_time = excluded.tee_time,
  published = excluded.published,
  notes = excluded.notes,
  updated_at = excluded.updated_at;

on conflict (id) do nothing;

on conflict (id) do update set
  format = excluded.format,
  result = excluded.result,
  points_for = excluded.points_for,
  points_against = excluded.points_against;

on conflict (id) do update set
  round_id = excluded.round_id,
  match_id = excluded.match_id,
  title = excluded.title,
  description = excluded.description,
  market_type = excluded.market_type,
  status = excluded.status,
  closes_at = excluded.closes_at,
  result_option_id = excluded.result_option_id,
  result_text = excluded.result_text,
  updated_at = excluded.updated_at;

on conflict (id) do update set
  label = excluded.label,
  linked_player_id = excluded.linked_player_id,
  linked_team_id = excluded.linked_team_id,
  linked_match_side = excluded.linked_match_side,
  sort_order = excluded.sort_order;

on conflict (id) do update set
  title = excluded.title,
  body = excluded.body,
  sort_order = excluded.sort_order,
  updated_at = excluded.updated_at;

on conflict (id) do update set
  item_date = excluded.item_date,
  day_label = excluded.day_label,
  time_label = excluded.time_label,
  activity = excluded.activity,
  location = excluded.location,
  notes = excluded.notes,
  is_placeholder = excluded.is_placeholder,
  sort_order = excluded.sort_order,
  updated_at = excluded.updated_at;

on conflict (id) do update set
  colour_label = excluded.colour_label,
  sort_order = excluded.sort_order;

commit;
